// public/firebase-messaging-sw.template.js
// This file MUST be in the /public folder so it's served at the root
// DO NOT put secrets here. The real SW is generated by next.config.js from this template.

importScripts('https://www.gstatic.com/firebasejs/10.12.0/firebase-app-compat.js');
importScripts('https://www.gstatic.com/firebasejs/10.12.0/firebase-messaging-compat.js');

firebase.initializeApp({
  apiKey: "%%NEXT_PUBLIC_FIREBASE_API_KEY%%",
  authDomain: "%%NEXT_PUBLIC_FIREBASE_AUTH_DOMAIN%%",
  databaseURL: "%%NEXT_PUBLIC_FIREBASE_DATABASE_URL%%",
  projectId: "%%NEXT_PUBLIC_FIREBASE_PROJECT_ID%%",
  storageBucket: "%%NEXT_PUBLIC_FIREBASE_STORAGE_BUCKET%%",
  messagingSenderId: "%%NEXT_PUBLIC_FIREBASE_MESSAGING_SENDER_ID%%",
  appId: "%%NEXT_PUBLIC_FIREBASE_APP_ID%%"
});

const messaging = firebase.messaging();

// Handle background messages
messaging.onBackgroundMessage((payload) => {
  const { title, body, icon } = payload.notification;

  const notificationOptions = {
    body: body || 'Motion detected!',
    icon: icon || '/icon-192.png',
    badge: '/icon-192.png',
    vibrate: [200, 100, 200],
    tag: 'safe360-alert',
    renotify: true,
    data: payload.data
  };

  self.registration.showNotification(title || 'Safe360 Alert', notificationOptions);
});

// Click on notification opens the app
self.addEventListener('notificationclick', (event) => {
  event.notification.close();
  event.waitUntil(
    clients.openWindow('/')
  );
});
